plugins.source_code:
desc:GFX Test - VU Meter
slider1:0<-60,12,0.1>Gain (dB)

@slider
gain = 10^(slider1/20);

@sample
spl0 *= gain;
spl1 *= gain;
peak_l = max(peak_l, abs(spl0));
peak_r = max(peak_r, abs(spl1));

@gfx 400 300
gfx_clear = 0x1a1a2e;

// Title
gfx_r = 0.9; gfx_g = 0.9; gfx_b = 0.95; gfx_a = 1;
gfx_x = 10; gfx_y = 10;
gfx_drawstr("JSFX GFX Test - VU Meter");

// Meter background
gfx_r = 0.15; gfx_g = 0.15; gfx_b = 0.2;
gfx_rect(30, 50, 340, 30);
gfx_rect(30, 100, 340, 30);

// Meter fill - left
bar_l = min(peak_l * 340, 340);
bar_l > 300 ? (gfx_r = 1; gfx_g = 0.2; gfx_b = 0.2) :
bar_l > 240 ? (gfx_r = 1; gfx_g = 0.8; gfx_b = 0.2) :
(gfx_r = 0.2; gfx_g = 0.8; gfx_b = 0.4);
gfx_rect(30, 50, bar_l, 30);

// Meter fill - right
bar_r = min(peak_r * 340, 340);
bar_r > 300 ? (gfx_r = 1; gfx_g = 0.2; gfx_b = 0.2) :
bar_r > 240 ? (gfx_r = 1; gfx_g = 0.8; gfx_b = 0.2) :
(gfx_r = 0.2; gfx_g = 0.8; gfx_b = 0.4);
gfx_rect(30, 100, bar_r, 30);

// Labels
gfx_r = 0.7; gfx_g = 0.7; gfx_b = 0.75;
gfx_x = 30; gfx_y = 35;
gfx_drawstr("L");
gfx_x = 30; gfx_y = 85;
gfx_drawstr("R");

// Slider value display
gfx_x = 30; gfx_y = 150;
gfx_r = 0.9; gfx_g = 0.9; gfx_b = 0.95;
gfx_printf("Gain: %.1f dB", slider1);

// Mouse position display
gfx_x = 30; gfx_y = 180;
gfx_printf("Mouse: %d, %d", mouse_x, mouse_y);

// Mouse button indicator
mouse_cap & 1 ? (
  gfx_r = 0.2; gfx_g = 0.8; gfx_b = 1;
  gfx_circle(mouse_x, mouse_y, 10, 1);
);

// Decay peaks
peak_l *= 0.95;
peak_r *= 0.95;
